// Substantive bilingual household guides for major festivals that previously
// resolved only to calendar metadata. Editorial sources and scope decisions are
// recorded in plans/major-festival-guide-research.md.

const p = (en, hi) => ({ en, hi });
const list = (items) => items.map(([en, hi]) => p(en, hi));
const guide = (x) => ({
  verdict: p(...x.verdict), meaning: p(...x.meaning), vidhi: list(x.vidhi),
  diet: p(...x.diet), sankalpa: p(...x.sankalpa), puja: p(...x.puja),
  stories: list(x.stories), regional: list(x.regional), paran: p(...x.paran),
  udyapan: p(...x.udyapan), safety: p(...x.safety),
});

const commonCompletion = {
  udyapan: ["An annual household observance needs no separate udyapan. Complete a specially counted or teacher-given vow with the family, temple or teacher who gave its rules.", "वार्षिक गृह-अनुष्ठान में अलग उद्यापन आवश्यक नहीं। विशेष गिनती या गुरु से मिले संकल्प का समापन उसी परिवार, मंदिर या गुरु की विधि से करें।"],
  safety: ["This note does not change the religious observance. Keep medicines and medically required food or water on schedule; use safe, accessible places and do not let crowds, smoke, flame or strenuous fasting endanger anyone.", "यह टिप्पणी धार्मिक अनुष्ठान को नहीं बदलती। दवा और चिकित्सकीय आवश्यक आहार-जल समय पर लें; सुरक्षित, सुलभ स्थान चुनें और भीड़, धुआँ, अग्नि या कठोर व्रत से किसी को संकट में न डालें।"],
};

